SELECT part_number
FROM springs
WHERE wire_size > '0.016';

SELECT spring_material, COUNT(*) AS material_count
FROM spring_materials
GROUP BY spring_material;

SELECT AVG(CAST(wire_size AS REAL)) AS avg_wire_size
FROM springs
WHERE part_number = '0';

SELECT part_number
FROM production_batches
WHERE batch_id > 1;

SELECT COUNT(*) 
FROM springs 
WHERE spring_type_id = 1;

SELECT COUNT(*) AS total_springs
FROM springs
WHERE part_number = '0';
